import { Router } from 'express';
import { discoverAdvisors, getTrustScore, computeTrustScore, getLeaderboard, getStrategyDNA, getVerifiedProfile } from '../controllers/AdvisorIntelligenceController.js';
import { authenticate } from '../middleware/authMiddleware.js';
const router = Router();
router.get('/discovery', authenticate, discoverAdvisors);
router.get('/trust-score/:id', getTrustScore);
router.post('/trust-score/:id/compute', authenticate, computeTrustScore);
router.get('/leaderboard', getLeaderboard);
router.get('/strategy-dna/:id', getStrategyDNA);
router.get('/performance/:id', authenticate, getVerifiedProfile);
export default router;
